<html lang="zh-CN">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>忘记密码 - MyApp</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: -apple-system, sans-serif; display: flex; justify-content: center; align-items: center; min-height: 100vh; background: #f5f5f5; }
    .container { width: 100%; max-width: 400px; padding: 20px; }
    .card { background: #fff; border-radius: 12px; padding: 32px; box-shadow: 0 2px 12px rgba(0,0,0,0.08); }
    h1 { text-align: center; margin-bottom: 24px; font-size: 24px; color: #333; }
    .form-group { margin-bottom: 16px; }
    label { display: block; margin-bottom: 6px; font-size: 14px; color: #666; }
    input { width: 100%; padding: 10px 12px; border: 1px solid #ddd; border-radius: 8px; font-size: 16px; outline: none; }
    input:focus { border-color: #4F4AFC; }
    .btn { width: 100%; padding: 12px; background: #4F4AFC; color: #fff; border: none; border-radius: 8px; font-size: 16px; cursor: pointer; }
    .btn:hover { background: #3d38d6; }
    .error { color: #e53e3e; font-size: 13px; margin-top: 4px; display: none; }
    .success-msg { background: #c6f6d5; color: #276749; padding: 12px; border-radius: 8px; text-align: center; margin-top: 16px; display: none; }
    .back-link { display: block; text-align: center; margin-top: 16px; font-size: 14px; }
    .back-link a { color: #4F4AFC; text-decoration: none; }
  </style>
</head>
<body>
  <div class="container">
    <div class="card">
      <h1>忘记密码</h1>
      <p style="text-align:center;color:#666;margin-bottom:20px;font-size:14px;">输入您的邮箱地址，我们将发送重置链接</p>
      <div class="form-group">
        <label for="reset-email">邮箱</label>
        <input type="email" id="reset-email" placeholder="请输入您的邮箱">
        <div class="error" id="email-error">请输入邮箱地址</div>
      </div>
      <button class="btn" onclick="handleReset()">发送重置链接</button>
      <div class="success-msg" id="success-msg">重置链接已发送，请检查您的邮箱</div>
      <div class="back-link"><a href="/login">返回登录</a></div>
    </div>
  </div>
  <script>
    function handleReset() {
      const email = document.getElementById('reset-email').value.trim();
      const error = document.getElementById('email-error');
      const success = document.getElementById('success-msg');
      error.style.display = 'none';
      success.style.display = 'none';
      if (!email) {
        error.textContent = '请输入邮箱地址';
        error.style.display = 'block';
        return;
      }
      if (!email.includes('@')) {
        error.textContent = '请输入有效的邮箱地址';
        error.style.display = 'block';
        return;
      }
      success.style.display = 'block';
    }
  </script>
</body>
</html>
